const crypto = require('crypto');
const headers = $json.headers || {};
const body = $json.body || $json;
const ts = headers['x-slack-request-timestamp'] || headers['X-Slack-Request-Timestamp'];
const sig = headers['x-slack-signature'] || headers['X-Slack-Signature'];
const secret = $env.SLACK_SIGNING_SECRET;

if (!secret) {
  throw new Error('SLACK_SIGNING_SECRET is not set');
}

if (!ts || !sig) {
  return [{ json: { isValid: false, reason: 'missing_signature_headers', body } }];
}

const age = Math.abs(Math.floor(Date.now() / 1000) - Number(ts));
if (!Number.isFinite(age) || age > 300) {
  return [{ json: { isValid: false, reason: 'stale_timestamp', body } }];
}

const rawBody = typeof body === 'string' ? body : new URLSearchParams(body).toString();
const baseString = `v0:${ts}:${rawBody}`;
const expected = `v0=${crypto.createHmac('sha256', secret).update(baseString).digest('hex')}`;
const provided = String(sig).trim();
const ok = (provided.length === expected.length) && crypto.timingSafeEqual(Buffer.from(provided), Buffer.from(expected));

return [{ json: { isValid: ok, reason: ok ? 'ok' : 'invalid_signature', body } }];

const body = $json.body || $json;
const rawText = String(body.text || '').trim();
const text = rawText.slice(0, 1000);

return [{
  json: {
    intent: 'onboard_user',
    agentId: 13,
    isSupported: true,
    command: '/onboard',
    text,
    learner: {
      slackUserId: body.user_id || null,
      userName: body.user_name || null
    },
    meta: {
      receivedAt: new Date().toISOString(),
      source: 'slack',
      requestId: body.trigger_id || body.api_app_id || null,
      textTruncated: rawText.length > 1000
    }
  }
}];
